#include <stdio.h>

#define MOD 1000000007

int calc(int n, int m, int k) {
    if (k == -1 && n % 2 != m % 2) {
        return 0;
    }
    n = (n - 1);
    m = (m - 1);
    n = (n * m);
    int r = 1;
    int s = 2;
    while (n > 0) {
        if (n % 2 == 1) {
            r = (1LL * r * s) % MOD;
        }
        n /= 2;
        s = (1LL * s * s) % MOD;
    }
    return r;
}

int main() {
    int n, m, k;
    scanf("%d %d %d", &n, &m, &k);
    printf("%d\n", calc(n, m, k));
    return 0;
}
